const paper = items[0].json;
const evalId = $node['Webhook Guide'].json.body.evaluation_id;

if (!paper || !paper.paper_text) {
  return [{ json: { error: 'Paper not found or no text available' } }];
}

// Truncate paper text to ~6000 words to fit in context
const words = paper.paper_text.split(/\s+/);
const truncated = words.length > 6000 ? words.slice(0, 6000).join(' ') + '\n[...truncated]' : paper.paper_text;

const scores = {
  overall: Number(paper.overall_score) || 0,
  knowledge: Number(paper.knowledge_score) || 0,
  critical: Number(paper.critical_score) || 0,
  application: Number(paper.application_score) || 0,
  referencing: Number(paper.referencing_score) || 0,
  structure: Number(paper.structure_score) || 0,
  ai_risk: paper.ai_risk_score !== null ? Number(paper.ai_risk_score) : null
};

// Find weakest areas (below 80)
const areas = [
  { key: 'knowledge', label: 'Knowledge & Understanding', score: scores.knowledge },
  { key: 'critical', label: 'Critical Thinking', score: scores.critical },
  { key: 'application', label: 'Application', score: scores.application },
  { key: 'referencing', label: 'Referencing', score: scores.referencing },
  { key: 'structure', label: 'Structure & Flow', score: scores.structure }
].filter(a => a.score < 80).sort((a, b) => a.score - b.score);

const weakAreas = areas.map(a => `${a.label}: ${a.score}%`).join(', ');

const systemPrompt = `You are a South African academic writing coach helping university students improve their papers to distinction level (80%+).

You will receive a student's paper and their evaluation scores. Your job is to:
1. Find SPECIFIC passages in their actual text that can be improved
2. Rewrite those passages to distinction level
3. Explain what you changed and why it earns more marks

Rules:
- Use the student's ACTUAL text — quote their exact words in "before" examples
- Rewrites must be realistic improvements, not perfect prose
- Focus on the weakest scoring areas first
- Maximum 5 improvement examples
- Each example must target a different scoring criterion
- South African academic context (use SA examples where relevant)
- Be encouraging but honest
- Keep the student's voice — improve, don't replace

Respond ONLY with valid JSON in this format:
{
  "target_score": 80,
  "current_score": <number>,
  "gap": <number>,
  "improvements": [
    {
      "criterion": "Knowledge" | "Critical Thinking" | "Application" | "Referencing" | "Structure",
      "current_score": <number>,
      "location": "<where in the paper — e.g. Introduction paragraph 2>",
      "before": "<exact quote from student's paper>",
      "after": "<your improved rewrite>",
      "why_better": "<1-2 sentences explaining what changed and why it scores higher>",
      "marks_impact": "<estimated mark gain — e.g. +3-5 marks>"
    }
  ],
  "overall_advice": "<2-3 sentences of general advice for this student>"
}`;

const userMessage = `Student paper (${paper.subject}, ${paper.assessment_type}, ${paper.word_count} words):

Scores: Overall ${scores.overall}%, Knowledge ${scores.knowledge}%, Critical ${scores.critical}%, Application ${scores.application}%, Referencing ${scores.referencing}%, Structure ${scores.structure}%${scores.ai_risk !== null ? ', AI Risk ' + scores.ai_risk + '%' : ''}

Weakest areas: ${weakAreas || 'All above 80%'}

---PAPER START---
${truncated}
---PAPER END---

Generate the distinction improvement guide. Focus on the weakest areas. Use EXACT quotes from the paper in your "before" examples.`;

return [{
  json: {
    systemPrompt,
    userMessage,
    paper_id: paper.id,
    evaluation_id: evalId,
    scores,
    subject: paper.subject
  }
}];

const response = items[0].json;
const upstream = $node['Build Guide Prompt'].json;

try {
  let text = '';
  if (response.content && response.content[0]) {
    text = response.content[0].text || '';
  }

  // Extract JSON from response (handle markdown code blocks)
  let jsonStr = text;
  const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) jsonStr = jsonMatch[1];

  // Try to find JSON object
  const objMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (objMatch) jsonStr = objMatch[0];

  const guide = JSON.parse(jsonStr);

  return [{
    json: {
      status: 'complete',
      evaluation_id: upstream.evaluation_id,
      paper_id: upstream.paper_id,
      subject: upstream.subject,
      target_score: guide.target_score || 80,
      current_score: guide.current_score || upstream.scores.overall,
      gap: guide.gap || (80 - (upstream.scores.overall || 0)),
      improvements: guide.improvements || [],
      overall_advice: guide.overall_advice || '',
      scores: upstream.scores
    }
  }];
} catch(e) {
  return [{
    json: {
      status: 'complete',
      evaluation_id: upstream.evaluation_id,
      paper_id: upstream.paper_id,
      subject: upstream.subject,
      target_score: 80,
      current_score: upstream.scores.overall,
      gap: 80 - (upstream.scores.overall || 0),
      improvements: [],
      overall_advice: 'We could not generate specific rewrites for this paper. Focus on the weakest areas identified in your evaluation report.',
      scores: upstream.scores,
      parse_error: e.message
    }
  }];
}
